PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE drive_accounts (
    id              TEXT PRIMARY KEY,
    user_id         TEXT NOT NULL REFERENCES "users_old"(id) ON DELETE CASCADE,
    google_account_id TEXT NOT NULL,
    email           TEXT NOT NULL,
    name            TEXT,
    type            TEXT NOT NULL DEFAULT 'oauth',
    is_primary      INTEGER NOT NULL DEFAULT 0,
    root_folder_id  TEXT,
    total_quota     INTEGER DEFAULT 0,
    used_quota      INTEGER DEFAULT 0,
    quota_updated_at TEXT,
    created_at      TEXT NOT NULL DEFAULT (datetime('now')),
    UNIQUE(user_id, google_account_id)
);
CREATE TABLE files (
    id              TEXT PRIMARY KEY,
    user_id         TEXT NOT NULL REFERENCES "users_old"(id) ON DELETE CASCADE,
    drive_account_id TEXT NOT NULL REFERENCES drive_accounts(id) ON DELETE CASCADE,
    google_file_id  TEXT NOT NULL,
    name            TEXT NOT NULL,
    mime_type       TEXT,
    size            INTEGER DEFAULT 0,
    thumbnail_url   TEXT,
    web_view_link   TEXT,
    web_content_link TEXT,
    is_trashed      INTEGER NOT NULL DEFAULT 0,
    google_created_at  TEXT,
    google_modified_at TEXT,
    synced_at       TEXT NOT NULL DEFAULT (datetime('now')),
    created_at      TEXT NOT NULL DEFAULT (datetime('now')), google_parent_id TEXT, is_starred INTEGER NOT NULL DEFAULT 0, updated_at TEXT NOT NULL DEFAULT '2024-01-01 00:00:00', workspace_id TEXT REFERENCES workspaces(id) ON DELETE CASCADE, workspace_folder_id TEXT REFERENCES workspace_folders(id) ON DELETE SET NULL,
    UNIQUE(drive_account_id, google_file_id)
);
CREATE TABLE sync_state (
    drive_account_id TEXT PRIMARY KEY REFERENCES drive_accounts(id) ON DELETE CASCADE,
    change_token     TEXT,
    last_synced_at   TEXT,
    status           TEXT DEFAULT 'idle',
    error_message    TEXT
);
CREATE TABLE drive_folders (
    id                TEXT PRIMARY KEY,
    drive_account_id  TEXT NOT NULL REFERENCES drive_accounts(id) ON DELETE CASCADE,
    google_folder_id  TEXT NOT NULL,
    google_parent_id  TEXT,
    name              TEXT NOT NULL,
    is_synced         INTEGER NOT NULL DEFAULT 0,
    synced_at         TEXT,
    created_at        TEXT NOT NULL DEFAULT (datetime('now')), virtual_folder_id TEXT REFERENCES virtual_folders(id) ON DELETE SET NULL,
    UNIQUE(drive_account_id, google_folder_id)
);
CREATE TABLE shared_links (
    id              TEXT PRIMARY KEY,
    user_id         TEXT NOT NULL REFERENCES "users_old"(id) ON DELETE CASCADE,
    target_type     TEXT NOT NULL CHECK (target_type IN ('file', 'folder')),
    target_id       TEXT NOT NULL,
    password_hash   TEXT,
    expires_at      TEXT,
    created_at      TEXT NOT NULL DEFAULT (datetime('now'))
, allow_downloads INTEGER NOT NULL DEFAULT 1, allow_uploads INTEGER NOT NULL DEFAULT 0, max_downloads INTEGER, require_email INTEGER NOT NULL DEFAULT 0, webhook_url TEXT, view_count INTEGER NOT NULL DEFAULT 0, download_count INTEGER NOT NULL DEFAULT 0);
CREATE TABLE automation_rules (
    id              TEXT PRIMARY KEY,
    user_id         TEXT NOT NULL REFERENCES "users_old"(id) ON DELETE CASCADE,
    name            TEXT NOT NULL,
    trigger_type    TEXT NOT NULL,
    trigger_config  TEXT,
    conditions      TEXT,
    actions         TEXT,
    is_active       INTEGER NOT NULL DEFAULT 1,
    created_at      TEXT NOT NULL DEFAULT (datetime('now')),
    updated_at      TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE automation_logs (
    id              TEXT PRIMARY KEY,
    rule_id         TEXT NOT NULL REFERENCES automation_rules(id) ON DELETE CASCADE,
    status          TEXT NOT NULL,
    details         TEXT,
    executed_at     TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE shared_link_logs (
    id              INTEGER PRIMARY KEY AUTOINCREMENT,
    shared_link_id  TEXT NOT NULL REFERENCES shared_links(id) ON DELETE CASCADE,
    action          TEXT NOT NULL,
    visitor_email   TEXT,
    created_at      TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE workspaces (
    id              TEXT PRIMARY KEY,
    name            TEXT NOT NULL,
    owner_id        TEXT NOT NULL REFERENCES "users_old"(id) ON DELETE CASCADE,
    created_at      TEXT NOT NULL DEFAULT (datetime('now')),
    updated_at      TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE workspace_members (
    id              TEXT PRIMARY KEY,
    workspace_id    TEXT NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE,
    user_id         TEXT NOT NULL REFERENCES "users_old"(id) ON DELETE CASCADE,
    role            TEXT NOT NULL CHECK (role IN ('owner', 'admin', 'member')),
    joined_at       TEXT NOT NULL DEFAULT (datetime('now')),
    UNIQUE(workspace_id, user_id)
);
CREATE TABLE workspace_folders (
    id              TEXT PRIMARY KEY,
    workspace_id    TEXT NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE,
    name            TEXT NOT NULL,
    parent_id       TEXT REFERENCES workspace_folders(id) ON DELETE CASCADE,
    icon            TEXT,
    color           TEXT,
    is_starred      INTEGER NOT NULL DEFAULT 0,
    created_at      TEXT NOT NULL DEFAULT (datetime('now')),
    updated_at      TEXT NOT NULL DEFAULT (datetime('now')),
    UNIQUE(workspace_id, parent_id, name)
);
CREATE TABLE users (
    id              TEXT PRIMARY KEY,
    username        TEXT UNIQUE NOT NULL,
    password_hash   TEXT NOT NULL,
    google_id       TEXT UNIQUE,
    email           TEXT UNIQUE,
    name            TEXT,
    avatar_url      TEXT,
    created_at      TEXT NOT NULL DEFAULT (datetime('now')),
    updated_at      TEXT NOT NULL DEFAULT (datetime('now'))
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_files_drive ON files(drive_account_id);
CREATE INDEX idx_files_name ON files(user_id, name);
CREATE INDEX idx_drives_user ON drive_accounts(user_id);
CREATE INDEX idx_files_google_parent ON files(drive_account_id, google_parent_id);
CREATE INDEX idx_drive_folders_parent ON drive_folders(drive_account_id, google_parent_id);
CREATE INDEX idx_shared_links_user ON shared_links(user_id);
CREATE INDEX idx_shared_links_target ON shared_links(target_type, target_id);
CREATE INDEX idx_automation_rules_user ON automation_rules(user_id);
CREATE INDEX idx_automation_rules_trigger ON automation_rules(trigger_type, is_active);
CREATE INDEX idx_automation_logs_rule ON automation_logs(rule_id);
CREATE INDEX idx_files_user_workspace ON files(user_id, workspace_id);
CREATE INDEX idx_files_workspace_folder ON files(workspace_folder_id);
CREATE INDEX idx_workspace_folders_parent ON workspace_folders(workspace_id, parent_id);
CREATE INDEX idx_workspace_members_user ON workspace_members(user_id);
